export { 
  createWindow, 
  closeWindow, 
  setupIpcHandlers, 
  setProjectRoot,
  startApp,
  projectRootPath 
}

/**
 * 事实提取服务
 * 自动从章节内容中提取战力、物品、关系、伏笔等事实
 */

import aiModelService from './aiModels'
import factsStore, { Fact } from '../db'

// 提取结果类型
export interface ExtractedFact extends Omit<Fact, 'id' | 'createdAt'> {
  confidence: number // 置信度 0-1
}

class FactExtractor {
  /**
   * 从章节内容提取事实
   */
  async extract(
    chapterContent: string,
    chapterNumber: number
  ): Promise<ExtractedFact[]> {
    try {
      const systemPrompt = `
你是小说事实提取专家。请从以下章节内容中提取关键事实信息，返回严格的JSON格式数组。

提取规则：
1. 战力信息(type="power")：角色的等级、实力、功法等
2. 物品信息(type="item")：武器、丹药、宝物等
3. 关系信息(type="relation")：角色之间的关系（朋友、敌人、师徒、夫妻等）
4. 伏笔信息(type="foreshadow")：后续可能用到的线索、未解开的谜团

每个事实必须包含：
- type: 类型（power/item/relation/foreshadow）
- subject: 主体（如"林枫"）
- object: 客体（可选，如"青云子"）
- content: 事实描述（如"林枫修炼到炼气三层"）
- chapterStart: 章节号（传入的 ${chapterNumber}）
- chapterEnd: 章节号（传入的 ${chapterNumber}）
- confidence: 置信度 0-1

返回格式示例：
[
  {
    "type": "power",
    "subject": "林枫",
    "object": "",
    "content": "林枫突破到炼气三层，实力提升三倍",
    "chapterStart": ${chapterNumber},
    "chapterEnd": ${chapterNumber},
    "confidence": 0.95
  }
]

只返回JSON，不要其他内容。
`

      const result = await aiModelService.call(
        'extraction',
        chapterContent,
        { systemPrompt }
      )

      if (!result.success || !result.content) {
        return []
      }

      // 解析提取结果
      let extractedFacts: ExtractedFact[]
      try {
        extractedFacts = JSON.parse(result.content.trim())
      } catch (parseError) {
        console.error('解析提取结果失败:', parseError)
        return []
      }

      return extractedFacts
    } catch (error) {
      console.error('事实提取失败:', error)
      return []
    }
  }

  /**
   * 批量保存事实到数据库
   */
  async saveFacts(facts: Omit<Fact, 'id' | 'createdAt'>[]): Promise<string[]> {
    const result = await factsStore.appendFacts(facts.map(f => ({
      type: f.type,
      subject: f.subject,
      object: f.object,
      content: f.content,
      chapterStart: f.chapterStart,
      chapterEnd: f.chapterEnd,
      confidence: 1.0,
    })))
    return result.success ? ['ok'] : []
  }

  /**
   * 自动提取并保存（用户确认后调用）
   */
  async extractAndSave(
    chapterContent: string,
    chapterNumber: number
  ): Promise<string[]> {
    const facts = await this.extract(chapterContent, chapterNumber)
    // 过滤置信度低于0.7的结果
    const highConfidenceFacts = facts.filter(f => f.confidence >= 0.7)
    return this.saveFacts(highConfidenceFacts)
  }

  /**
   * 验证事实一致性
   */
  async verifyConsistency(
    newFacts: ExtractedFact[],
    existingFacts: Fact[]
  ): Promise<Array<{ fact: ExtractedFact; conflict?: Fact; message: string }>> {
    const conflicts: Array<{ fact: ExtractedFact; conflict?: Fact; message: string }> = []

    for (const newFact of newFacts) {
      // 检查是否与现有事实冲突
      const conflicting = existingFacts.find(f => {
        if (f.subject !== newFact.subject) return false

        // 相同主体的战力信息冲突检查
        if (f.type === 'power' && newFact.type === 'power') {
          // 简单的冲突检测：如果新事实表明战力下降但没有合理解释
          const oldLevel = this.extractPowerLevel(f.content)
          const newLevel = this.extractPowerLevel(newFact.content)
          return oldLevel !== null && newLevel !== null && newLevel < oldLevel
        }

        // 关系信息冲突检查
        if (f.type === 'relation' && newFact.type === 'relation') {
          return f.object === newFact.object && f.content !== newFact.content
        }

        return false
      })

      if (conflicting) {
        conflicts.push({
          fact: newFact,
          conflict: conflicting,
          message: `检测到事实冲突：现有记录 "${conflicting.content}" 与新提取的 "${newFact.content}" 不一致`
        })
      }
    }

    return conflicts
  }

  /**
   * 辅助方法：提取战力等级
   */
  private extractPowerLevel(content: string): number | null {
    const regex = /炼气(\d+)/i
    const match = content.match(regex)
    if (match) return parseInt(match[1])

    const regex2 = /筑基(\d+)/i
    const match2 = content.match(regex2)
    if (match2) return parseInt(match2[1]) + 10 // 筑基阶段+10

    return null
  }
}

// 单例导出
const factExtractor = new FactExtractor()
export default factExtractor

/**
 * AI 服务 - 主进程 IPC 处理器
 * 处理渲染进程发来的 AI 相关 IPC 调用
 */

import { IpcMain, BrowserWindow } from 'electron'
import axios, { AxiosError } from 'axios'
import fs from 'node:fs'
import path from 'node:path'
import os from 'node:os'
import { app } from 'electron'

// ─── 配置路径 ────────────────────────────────────────────────────────────────

function getSettingsPath(): string {
  return path.join(app.getPath('userData'), 'ai-settings.json')
}

// ─── 配置读写 ────────────────────────────────────────────────────────────────

interface AiSettings {
  deepseekApiKey?: string
  doubaoApiKey?: string
  [key: string]: string | undefined
}

function loadSettings(): AiSettings {
  const p = getSettingsPath()
  if (fs.existsSync(p)) {
    try {
      return JSON.parse(fs.readFileSync(p, 'utf-8'))
    } catch {
      return {}
    }
  }
  return {}
}

function saveSettings(settings: AiSettings): void {
  const p = getSettingsPath()
  fs.mkdirSync(path.dirname(p), { recursive: true })
  fs.writeFileSync(p, JSON.stringify(settings, null, 2), 'utf-8')
}

// ─── API 调用 ────────────────────────────────────────────────────────────────

interface CallOptions {
  model?: string
  systemPrompt?: string
  temperature?: number
  maxTokens?: number
  topP?: number
  presencePenalty?: number
  frequencyPenalty?: number
}

async function callAI(
  prompt: string,
  options: CallOptions = {}
): Promise<{ success: boolean; content?: string; reasoning?: string; error?: string }> {
  const { model = 'deepseek', systemPrompt, temperature = 0.7, maxTokens = 2000 } = options

  const apiKey = loadSettings()[`${model}ApiKey`]
    || process.env.DEEPSEEK_API_KEY
    || process.env.DOUBAO_API_KEY

  if (!apiKey) {
    return {
      success: false,
      error: `未配置 API Key。请先在设置中配置 ${model} 的 API Key。`,
    }
  }

  try {
    const isDeepSeek = model === 'deepseek' || model === 'deepseek-chat' || model === 'deepseek-reasoner'
    if (isDeepSeek) {
      const deepseekModel = model === 'deepseek-reasoner' ? 'deepseek-reasoner' : 'deepseek-chat'
      const response = await axios.post(
        'https://api.deepseek.com/v1/chat/completions',
        {
          model: deepseekModel,
          messages: [
            ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
            { role: 'user', content: prompt },
          ],
          temperature,
          max_tokens: maxTokens,
        },
        {
          headers: {
            Authorization: `Bearer ${apiKey}`,
            'Content-Type': 'application/json',
          },
          timeout: 60000,
        }
      )
      return { success: true, content: response.data.choices[0]?.message?.content || '' }
    }

    if (model === 'doubao-pro' || model === 'doubao-lite' || model === 'doubao-mini') {
      const endpoint = model === 'doubao-pro'
        ? 'https://ark.cn-beijing.volces.com/api/v3/chat/completions'
        : 'https://ark.cn-beijing.volces.com/api/v3/chat/completions'

      const doubaoModel = model === 'doubao-pro'
        ? 'doubao-pro-32k'
        : model === 'doubao-lite'
          ? 'doubao-lite-32k'
          : 'doubao-mini'

      const response = await axios.post(
        endpoint,
        {
          model: doubaoModel,
          messages: [
            ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
            { role: 'user', content: prompt },
          ],
          temperature,
          max_tokens: maxTokens,
        },
        {
          headers: {
            Authorization: `Bearer ${apiKey}`,
            'Content-Type': 'application/json',
          },
          timeout: 60000,
        }
      )
      return { success: true, content: response.data.choices[0]?.message?.content || '' }
    }

    return { success: false, error: `不支持的模型: ${model}` }
  } catch (err) {
    const axiosErr = err as AxiosError
    if (axiosErr.response) {
      return { success: false, error: `API 错误 ${axiosErr.response.status}: ${JSON.stringify(axiosErr.response.data)}` }
    }
    return { success: false, error: `请求失败: ${axiosErr.message}` }
  }
}

async function streamAI(
  prompt: string,
  options: CallOptions,
  sendChunk: (content: string, done: boolean, reasoning?: string) => void,
  sendError: (error: string) => void
): Promise<void> {
  const { model = 'deepseek', systemPrompt, temperature = 0.7, maxTokens = 2000 } = options

  const apiKey = loadSettings()[`${model}ApiKey`]
    || process.env.DEEPSEEK_API_KEY
    || process.env.DOUBAO_API_KEY

  if (!apiKey) {
    sendError(`未配置 API Key。请先在设置中配置 ${model} 的 API Key。`)
    sendChunk('', true)
    return
  }

  try {
    const isDeepSeek = model === 'deepseek' || model === 'deepseek-chat' || model === 'deepseek-reasoner'
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${apiKey}`,
    }

    const body: Record<string, unknown> = {
      model: isDeepSeek
        ? (model === 'deepseek-reasoner' ? 'deepseek-reasoner' : 'deepseek-chat')
        : 'doubao-pro-32k',
      messages: [
        ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
        { role: 'user', content: prompt },
      ],
      temperature,
      max_tokens: maxTokens,
    }

    // DeepSeek（实际也是火山引擎 Doubao 端）支持流式
    if (isDeepSeek) {
      body.stream = true

      const response = await axios.post(
        'https://api.deepseek.com/v1/chat/completions',
        body,
        {
          headers,
          responseType: 'stream',
          timeout: 120000,
        }
      )

      const stream = response.data as import('node:stream').Stream
      let buffer = ''

      await new Promise<void>((resolve, reject) => {
        stream.on('data', (chunk: Buffer) => {
          buffer += chunk.toString()
          const lines = buffer.split('\n')
          buffer = lines.pop() || ''

          for (const line of lines) {
            const trimmed = line.trim()
            if (!trimmed || trimmed === 'data: [DONE]') continue
            if (!trimmed.startsWith('data: ')) continue
            const data = trimmed.slice(6)
            try {
              const parsed = JSON.parse(data)
              const content = parsed.choices?.[0]?.delta?.content || ''
              const reasoning = parsed.choices?.[0]?.delta?.reasoning || ''
              if (content || reasoning) {
                sendChunk(content, false, reasoning)
              }
            } catch {}
          }
        })

        stream.on('end', () => {
          if (buffer.trim() && buffer.trim() !== '[DONE]') {
            try {
              const data = JSON.parse(buffer.slice(6))
              const content = data.choices?.[0]?.delta?.content || ''
              if (content) sendChunk(content, false)
            } catch {}
          }
          sendChunk('', true)
          resolve()
        })

        stream.on('error', (err: Error) => {
          sendError(err.message)
          sendChunk('', true)
          resolve()
        })
      })
    } else {
      // 非流式降级
      const result = await callAI(prompt, options)
      if (result.success) {
        sendChunk(result.content || '', false)
        sendChunk('', true)
      } else {
        sendError(result.error || '未知错误')
        sendChunk('', true)
      }
    }
  } catch (err) {
    const axiosErr = err as AxiosError
    sendError(axiosErr.message || '请求失败')
    sendChunk('', true)
  }
}

// ─── IPC 处理器 ──────────────────────────────────────────────────────────────

export function setupAiHandlers(ipcMain: IpcMain): void {
  // 保存 API Key
  ipcMain.handle('ai:saveApiKey', async (_event, service: string, apiKey: string) => {
    try {
      const settings = loadSettings()
      settings[`${service}ApiKey`] = apiKey
      saveSettings(settings)
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 检查是否已配置
  ipcMain.handle('ai:isConfigured', async (_event, service: string) => {
    const settings = loadSettings()
    const configured = !!(settings[`${service}ApiKey`] || process.env[`${service.toUpperCase()}_API_KEY`])
    return { success: true, configured }
  })

  // 获取已配置的服务列表
  ipcMain.handle('ai:getConfiguredServices', async () => {
    const settings = loadSettings()
    const services: string[] = []
    if (settings.deepseekApiKey || process.env.DEEPSEEK_API_KEY) services.push('deepseek')
    if (settings.doubaoApiKey || process.env.DOUBAO_API_KEY) services.push('doubao')
    return { success: true, services }
  })

  // AI 调用（非流式）
  ipcMain.handle('ai:call', async (_event, prompt: string, options?: CallOptions) => {
    return callAI(prompt, options || {})
  })

  // AI 流式调用
  ipcMain.handle('ai:stream', async (event, prompt: string, options?: CallOptions) => {
    const win = BrowserWindow.fromWebContents(event.sender)
    if (!win || win.isDestroyed()) return { success: false, error: '窗口已关闭' }

    await streamAI(
      prompt,
      options || {},
      (content, done, reasoning) => {
        if (!win.isDestroyed()) {
          win.webContents.send('ai:stream-chunk', { content, done, reasoning })
        }
      },
      (error) => {
        if (!win.isDestroyed()) {
          win.webContents.send('ai:stream-error', error)
        }
      }
    )

    return { success: true }
  })

  // 测试连接
  ipcMain.handle('ai:testConnection', async (_event, service: string) => {
    const testPrompt = '请回复"连接成功"，不需要其他内容。'
    const result = await callAI(testPrompt, { model: service, maxTokens: 50 })
    return { success: result.success, result: result.success, error: result.error }
  })

  // 保存设置
  ipcMain.handle('ai:saveSetting', async (_event, key: string, value: any) => {
    try {
      const settings = loadSettings()
      settings[key] = value
      saveSettings(settings)
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 读取设置
  ipcMain.handle('ai:getSetting', async (_event, key: string, defaultValue?: any) => {
    const settings = loadSettings()
    return { success: true, value: settings[key] ?? defaultValue }
  })
}

/**
 * YAML 服务 - 主进程 IPC 处理器
 * 提供 YAML 文件的安全读写，解析和序列化
 * 所有路径操作必须经过 validatePath 验证，防止目录遍历攻击
 */

import { IpcMain } from 'electron'
import fs from 'node:fs'
import path from 'node:path'
import yaml from 'js-yaml'

// ─── 路径验证（与 index.ts 保持一致） ───────────────────────────────────────

function validateYamlPath(requestedPath: string): { valid: boolean; resolvedPath?: string; error?: string } {
  // yamlService 只允许操作项目子目录下的 facts/ 目录
  //  Facts 目录固定在 {projectRoot}/facts/
  // 但由于 yamlService 不持有 projectRoot，需要由调用方（factsStore）保证传入合法路径
  // 这里做最后一道防线：禁止跨盘符访问和敏感路径
  const normalized = path.normalize(path.resolve(requestedPath))

  const sensitivePaths = [
    'C:\\Windows',
    'C:\\Program Files',
    '/etc',
    '/usr',
    '/root',
    '/home',
  ]

  for (const sensitive of sensitivePaths) {
    if (normalized.toLowerCase().startsWith(sensitive.toLowerCase())) {
      return { valid: false, error: `禁止访问系统路径: ${sensitive}` }
    }
  }

  return { valid: true, resolvedPath: normalized }
}

// ─── IPC 处理器 ──────────────────────────────────────────────────────────────

export function setupYamlHandlers(ipcMain: IpcMain): void {
  ipcMain.handle('yaml:read', async (_event, filePath: string): Promise<{ success: boolean; data?: any; error?: string }> => {
    try {
      const validation = validateYamlPath(filePath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }
      if (!fs.existsSync(validation.resolvedPath!)) {
        return { success: false, error: '文件不存在' }
      }
      const content = fs.readFileSync(validation.resolvedPath!, 'utf-8')
      const data = yaml.load(content)
      return { success: true, data }
    } catch (e: any) {
      return { success: false, error: `YAML 解析失败: ${e.message}` }
    }
  })

  ipcMain.handle('yaml:write', async (_event, filePath: string, data: any): Promise<{ success: boolean; error?: string }> => {
    try {
      const validation = validateYamlPath(filePath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }
      const dir = path.dirname(validation.resolvedPath!)
      if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true })
      }
      const yamlStr = yaml.dump(data)
      fs.writeFileSync(validation.resolvedPath!, yamlStr, 'utf-8')
      return { success: true }
    } catch (e: any) {
      return { success: false, error: `YAML 写入失败: ${e.message}` }
    }
  })
}

/**
 * 备份服务 - 主进程 IPC 处理器
 * 处理小说项目的备份/恢复
 */

import { IpcMain, app } from 'electron'
import fs from 'node:fs'
import path from 'node:path'
import zlib from 'node:zlib'
import { promisify } from 'node:util'

const gzip = promisify(zlib.gzip)
const gunzip = promisify(zlib.gunzip)

const BACKUP_DIR = path.join(app.getPath('userData'), 'backups')
const BACKUP_INDEX = path.join(BACKUP_DIR, 'index.json')

interface BackupEntry {
  name: string
  path: string
  date: string
  size: number
  description?: string
}

function loadIndex(): BackupEntry[] {
  if (!fs.existsSync(BACKUP_INDEX)) return []
  try {
    return JSON.parse(fs.readFileSync(BACKUP_INDEX, 'utf-8'))
  } catch {
    return []
  }
}

function saveIndex(index: BackupEntry[]): void {
  fs.mkdirSync(BACKUP_DIR, { recursive: true })
  fs.writeFileSync(BACKUP_INDEX, JSON.stringify(index, null, 2), 'utf-8')
}

// 递归压缩目录为一个 gzip 文件
async function compressDir(dirPath: string, relativeRoot: string): Promise<Buffer> {
  const entries: { path: string; relativePath: string; isDir: boolean }[] = []

  function walk(dir: string): void {
    const items = fs.readdirSync(dir)
    for (const item of items) {
      const full = path.join(dir, item)
      const rel = path.relative(relativeRoot, full)
      const stat = fs.statSync(full)
      if (stat.isDirectory()) {
        entries.push({ path: full, relativePath: rel + '/', isDir: true })
        walk(full)
      } else {
        entries.push({ path: full, relativePath: rel, isDir: false })
      }
    }
  }
  walk(dirPath)

  // 构建文件列表 JSON
  const manifest = JSON.stringify(entries, null, 2)
  const manifestBuf = Buffer.from(manifest, 'utf-8')

  const parts: Buffer[] = []
  // 格式：4字节manifest长度 + manifest JSON + 各文件内容
  const manifestLenBuf = Buffer.alloc(4)
  manifestLenBuf.writeUInt32BE(manifestBuf.length, 0)
  parts.push(manifestLenBuf, manifestBuf)

  for (const entry of entries) {
    if (entry.isDir) continue
    const content = fs.readFileSync(entry.path)
    const nameBuf = Buffer.from(entry.relativePath, 'utf-8')
    const nameLenBuf = Buffer.alloc(2)
    nameLenBuf.writeUInt16BE(nameBuf.length, 0)
    const sizeBuf = Buffer.alloc(4)
    sizeBuf.writeUInt32BE(content.length, 0)
    parts.push(nameLenBuf, nameBuf, sizeBuf, content)
  }

  const combined = Buffer.concat(parts)
  return gzip(combined)
}

async function decompressBackup(
  archivePath: string,
  targetDir: string
): Promise<void> {
  const raw = fs.readFileSync(archivePath)
  const decompressed = await gunzip(raw)

  let offset = 0

  // 读取 manifest
  const manifestLen = decompressed.readUInt32BE(offset)
  offset += 4
  const manifest = JSON.parse(decompressed.slice(offset, offset + manifestLen).toString('utf-8'))
  offset += manifestLen

  // 清空目标目录
  if (fs.existsSync(targetDir)) {
    fs.rmSync(targetDir, { recursive: true })
  }
  fs.mkdirSync(targetDir, { recursive: true })

  // 恢复每个文件
  for (const entry of manifest) {
    if (entry.isDir) {
      fs.mkdirSync(path.join(targetDir, entry.relativePath), { recursive: true })
      continue
    }

    const nameLen = decompressed.readUInt16BE(offset)
    offset += 2
    // skip name (already have from manifest)
    offset += nameLen
    const size = decompressed.readUInt32BE(offset)
    offset += 4
    const content = decompressed.slice(offset, offset + size)
    offset += size

    const fullPath = path.join(targetDir, entry.relativePath)
    fs.mkdirSync(path.dirname(fullPath), { recursive: true })
    fs.writeFileSync(fullPath, content)
  }
}

function getBackupSize(archivePath: string): number {
  try {
    return fs.statSync(archivePath).size
  } catch {
    return 0
  }
}

export function setupBackupHandlers(ipcMain: IpcMain): void {
  // 创建备份
  ipcMain.handle('backup:create', async (_event, projectPath?: string) => {
    try {
      if (!projectPath) {
        return { success: false, error: '未提供项目路径' }
      }
      if (!fs.existsSync(projectPath)) {
        return { success: false, error: '项目路径不存在' }
      }

      fs.mkdirSync(BACKUP_DIR, { recursive: true })

      const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19)
      const name = path.basename(projectPath) + '_' + timestamp
      const archivePath = path.join(BACKUP_DIR, name + '.nbackup')

      const archive = await compressDir(projectPath, projectPath)
      fs.writeFileSync(archivePath, archive)

      const entry: BackupEntry = {
        name,
        path: archivePath,
        date: new Date().toISOString(),
        size: archive.length,
      }

      const index = loadIndex()
      index.unshift(entry)
      saveIndex(index)

      return { success: true, backupPath: archivePath }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 列出备份
  ipcMain.handle('backup:list', async () => {
    try {
      const index = loadIndex()
      // 清理不存在的备份记录
      const valid = index.filter(e => fs.existsSync(e.path))
      if (valid.length !== index.length) {
        saveIndex(valid)
      }
      return {
        success: true,
        backups: valid.map(e => ({
          name: e.name,
          path: e.path,
          date: e.date,
          size: e.size,
        })),
      }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 恢复备份
  ipcMain.handle('backup:restore', async (_event, backupPath: string, targetPath?: string) => {
    try {
      if (!fs.existsSync(backupPath)) {
        return { success: false, error: '备份文件不存在' }
      }
      if (!targetPath) {
        return { success: false, error: '未提供恢复目标路径' }
      }
      // 验证目标路径安全（防止路径遍历）
      const resolved = path.resolve(targetPath)
      if (resolved.startsWith('/etc') || resolved.match(/^[A-Z]:\\(Windows|Program Files)/i)) {
        return { success: false, error: '禁止恢复到系统路径' }
      }

      await decompressBackup(backupPath, targetPath)
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 删除备份
  ipcMain.handle('backup:delete', async (_event, backupPath: string) => {
    try {
      if (fs.existsSync(backupPath)) {
        fs.unlinkSync(backupPath)
      }
      const index = loadIndex()
      saveIndex(index.filter(e => e.path !== backupPath))
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })
}
